class DSU {
    vector<int> parent;
    vector<int> rank;
public:
    DSU(int n) : parent(n+1), rank(n+1, 0) {
        for (int i=1; i<=n; ++i) parent[i] = i;
    }
    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }
    void union_(int x, int y) {
        int root_x = find(x);
        int root_y = find(y);
        if (root_x != root_y) {
            if (rank[root_x] < rank[root_y]) {
                parent[root_x] = root_y;
            } else {
                parent[root_y] = root_x;
                if (rank[root_x] == rank[root_y]) {
                    ++rank[root_x];
                }
            }
        }
    }
