    DSU dsu(c);
    for (const auto& conn : connections) {
        long long u = conn[0];
        long long v = conn[1];
        dsu.union_(u, v);
    }

    map<long long, multiset<long long>> component_multisets;
    for (long long i = 1; i <= c; ++i) {
        long long root = dsu.find(i);
        component_multisets[root].insert(i);
    }

    vector<long long> result;
    for (const auto& query : queries) {
        long long type = query[0];
        long long x = query[1];
        if (type == 1) {
            long long root = dsu.find(x);
            auto& ms = component_multisets[root];
            if (ms.empty()) {
                result.push_back(-1);
            } else {
                result.push_back(*ms.begin());
            }
        } else {
            long long root = dsu.find(x);
            auto& ms = component_multisets[root];
            ms.erase(x);
        }
    }
    return result;
}
