vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    vector<vector<long long>> adj(c + 1);
    for (auto& conn : connections) {
        long long u = conn[0];
        long long v = conn[1];
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    vector<int> component_id(c + 1, -1);
    int current_component = 0;
    vector<vector<long long>> component_stations;
    for (int i = 1; i <= c; ++i) {
        if (component_id[i] == -1) {
            queue<int> q;
            q.push(i);
            component_id[i] = current_component;
            vector<long long> comp;
            while (!q.empty()) {
                int u = q.front();
                q.pop();
                comp.push_back(u);
                for (long long v : adj[u]) {
                    if (component_id[v] == -1) {
                        component_id[v] = current_component;
                        q.push(v);
                    }
                }
            }
            component_stations.push_back(comp);
            current_component++;
        }
    }

    vector<set<long long>> component_sets;
    for (auto& comp : component_stations) {
        set<long long> s(comp.begin(), comp.end());
        component_sets.push_back(s);
    }

    vector<bool> online(c + 1, true);

    vector<long long> res;
    for (auto& q : queries) {
        if (q[0] == 1) {
            long long x = q[1];
            if (online[x]) {
                res.push_back(x);
            } else {
                int comp = component_id[x];
                if (component_sets[comp].empty()) {
                    res.push_back(-1);
                } else {
                    res.push_back(*component_sets[comp].begin());
                }
            }
        } else {
            long long x = q[1];
            online[x] = false;
            int comp = component_id[x];
            component_sets[comp].erase(x);
        }
    }

    return res;
}
